GameWithered = class("GameWither", GameMount)

function GameWithered:onCreate(id, position, player)
    self.entityId = EngineWorld:addFloatingMount(position, player:getYaw(), id, function(entity)
        player.entityPlayerMP:getOnFloatingMount(entity)
    end)
    self.lastFreeSkillTime = GameConfig.lastTntTime
end

function GameWithered:takeOffMount()
    local player = PlayerManager:getPlayerByUserId(self.userId)
    if not player or not player.entityPlayerMP then
        return
    end
    player.entityPlayerMP:getOffFloatingMount()
end

function GameWithered:getSkillPosition(entity)
    local player = PlayerManager:getPlayerByUserId(self.userId)
    if not player then
        return
    end

    local position = entity:getPosition()
    position.y = position.y + GameConfig.witheredVelocity

    return position
end

function GameWithered:onMountNotEnoughTime()
    local player = PlayerManager:getPlayerByUserId(self.userId)
    if not player then
        return
    end
    MsgSender.sendCenterTipsToTarget(player.rakssid, 5, Messages:msgNotEnoughTimeWithered())
end